using System.ComponentModel;
using System.Net.Http.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool, Description("Fetches data from an external API endpoint.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API path to query (e.g. '/users/1')")] string path,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path.TrimStart('/'), cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompt
{
    [McpServerPrompt, Description("Summarizes the provided text concisely.")]
    public static IList<McpServerPromptMessage> Summarize(
        [Description("The text content to summarize")] string content,
        [Description("Desired summary style: 'brief', 'detailed', or 'bullets'")] string style = "brief")
    {
        var systemInstruction = style switch
        {
            "detailed" => "Provide a detailed summary preserving key facts and nuance.",
            "bullets" => "Summarize the text as a bulleted list of key points.",
            _ => "Provide a brief one-paragraph summary."
        };

        return
        [
            new(McpServerPromptMessageRole.User,
                new($"<instructions>\n{systemInstruction}\n</instructions>\n\n<content>\n{content}\n</content>"))
        ];
    }
}

